import java.io.*;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Validate and sanitize the input command
            if (!isValidCommand(command)) {
                System.out.println("Invalid command. Please try again.");
                return;
            }

            Process process = Runtime.getRuntime().exec(command);

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static boolean isValidCommand(String command) {
        // Add your validation logic here
        // For example, you can restrict certain characters or commands
        // to prevent Command Injection attacks
        return !command.contains(";") && !command.contains("&");
    }
}

